import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import API from '../services/axios';

function Register() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ name: '', email: '', password: '', confirmPassword: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault(); setError('');
    if (formData.password !== formData.confirmPassword) { setError('Passwords do not match!'); return; }
    if (formData.password.length < 6) { setError('Password must be at least 6 characters.'); return; }
    setLoading(true);
    try {
      const res = await API.post('/auth/signup', { name: formData.name, email: formData.email, password: formData.password });
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('user', JSON.stringify(res.data.user));
      navigate('/home');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed. Try again.');
    } finally { setLoading(false); }
  };

  const inp = { width: '100%', padding: '13px 14px 13px 44px', background: 'rgba(255,255,255,0.07)', border: '1.5px solid rgba(255,255,255,0.1)', borderRadius: '12px', color: 'white', fontSize: '0.9rem', outline: 'none', boxSizing: 'border-box' };

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #0f0c29 0%, #1e1b4b 40%, #312e81 70%, #4c1d95 100%)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '2rem', fontFamily: "'Outfit', sans-serif", position: 'relative', overflow: 'hidden' }}>
      <div style={{ position: 'absolute', top: '-150px', left: '-100px', width: '450px', height: '450px', borderRadius: '50%', background: 'radial-gradient(circle, rgba(124,58,237,0.2) 0%, transparent 70%)', pointerEvents: 'none' }} />
      <div style={{ position: 'absolute', bottom: '-100px', right: '-150px', width: '400px', height: '400px', borderRadius: '50%', background: 'radial-gradient(circle, rgba(167,139,250,0.15) 0%, transparent 70%)', pointerEvents: 'none' }} />

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', maxWidth: '900px', width: '100%', borderRadius: '24px', overflow: 'hidden', boxShadow: '0 30px 80px rgba(0,0,0,0.5)', border: '1px solid rgba(255,255,255,0.1)' }}>

        {/* Left - Form */}
        <div style={{ background: 'rgba(15,12,41,0.97)', padding: '2.5rem', display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '1.5rem' }}>
            <div style={{ width: '38px', height: '38px', background: 'linear-gradient(135deg, #7c3aed, #a78bfa)', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: '800', color: 'white', fontSize: '1.1rem' }}>E</div>
            <span style={{ color: 'white', fontWeight: '700', fontSize: '1.2rem' }}>Event<span style={{ color: '#a78bfa' }}>Hub</span></span>
          </div>

          <h1 style={{ color: 'white', fontSize: '1.8rem', fontWeight: '800', marginBottom: '0.3rem' }}>Create Account</h1>
          <p style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.85rem', marginBottom: '1.5rem' }}>Join thousands of event lovers today</p>

          {error && <div style={{ background: 'rgba(239,68,68,0.15)', border: '1px solid rgba(239,68,68,0.3)', color: '#fca5a5', padding: '12px 16px', borderRadius: '12px', marginBottom: '1.2rem', fontSize: '0.85rem' }}>⚠️ {error}</div>}

          <form onSubmit={handleSubmit}>
            {[
              { label: 'FULL NAME', name: 'name', type: 'text', icon: '👤', placeholder: 'Your full name' },
              { label: 'EMAIL ADDRESS', name: 'email', type: 'email', icon: '📧', placeholder: 'you@example.com' },
              { label: 'PASSWORD', name: 'password', type: 'password', icon: '🔒', placeholder: 'Min 6 characters' },
              { label: 'CONFIRM PASSWORD', name: 'confirmPassword', type: 'password', icon: '✅', placeholder: 'Repeat your password' },
            ].map(field => (
              <div key={field.name} style={{ marginBottom: '1rem' }}>
                <label style={{ display: 'block', color: 'rgba(255,255,255,0.6)', fontSize: '0.72rem', fontWeight: '600', marginBottom: '6px', letterSpacing: '0.5px' }}>{field.label}</label>
                <div style={{ position: 'relative' }}>
                  <span style={{ position: 'absolute', left: '14px', top: '50%', transform: 'translateY(-50%)', fontSize: '0.9rem' }}>{field.icon}</span>
                  <input type={field.type} name={field.name} value={formData[field.name]} onChange={handleChange} required placeholder={field.placeholder} style={inp}
                    onFocus={e => e.target.style.borderColor = '#7c3aed'} onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.1)'} />
                </div>
              </div>
            ))}

            <button type="submit" disabled={loading} style={{ width: '100%', padding: '14px', background: 'linear-gradient(135deg, #7c3aed, #a78bfa)', color: 'white', border: 'none', borderRadius: '12px', fontWeight: '700', fontSize: '0.95rem', cursor: 'pointer', marginTop: '0.5rem', boxShadow: '0 8px 25px rgba(124,58,237,0.4)', opacity: loading ? 0.7 : 1 }}>
              {loading ? '⏳ Creating...' : '🎉 Create Account'}
            </button>
          </form>

          <div style={{ marginTop: '1.2rem', textAlign: 'center' }}>
            <span style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.85rem' }}>Already have an account? </span>
            <Link to="/login" style={{ color: '#a78bfa', fontWeight: '700', fontSize: '0.85rem', textDecoration: 'none' }}>Sign In →</Link>
          </div>
        </div>

        {/* Right - Purple Panel */}
        <div style={{ background: 'linear-gradient(135deg, #7c3aed 0%, #4c1d95 100%)', padding: '2.5rem', display: 'flex', flexDirection: 'column', justifyContent: 'center', position: 'relative', overflow: 'hidden' }}>
          <div style={{ position: 'absolute', top: '-60px', left: '-60px', width: '200px', height: '200px', borderRadius: '50%', background: 'rgba(255,255,255,0.08)' }} />
          <div style={{ position: 'absolute', bottom: '-40px', right: '-40px', width: '150px', height: '150px', borderRadius: '50%', background: 'rgba(255,255,255,0.05)' }} />

          <div style={{ position: 'relative' }}>
            <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🚀</div>
            <h2 style={{ color: 'white', fontSize: '1.8rem', fontWeight: '800', marginBottom: '1rem', lineHeight: '1.2' }}>Join the EventHub Community!</h2>
            <p style={{ color: 'rgba(255,255,255,0.7)', lineHeight: '1.7', marginBottom: '1.5rem', fontSize: '0.85rem' }}>Create your free account and start exploring thousands of amazing events happening around you.</p>

            {[
              { icon: '🆓', text: 'Free to join, no credit card needed' },
              { icon: '🔔', text: 'Get notified about new events' },
              { icon: '🎟️', text: 'Book tickets in seconds' },
              { icon: '⭐', text: 'Exclusive member-only deals' },
            ].map((f, i) => (
              <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '12px' }}>
                <div style={{ width: '34px', height: '34px', background: 'rgba(255,255,255,0.15)', borderRadius: '9px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.9rem', flexShrink: 0 }}>{f.icon}</div>
                <span style={{ color: 'rgba(255,255,255,0.85)', fontSize: '0.82rem', fontWeight: '500' }}>{f.text}</span>
              </div>
            ))}

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px', marginTop: '1.5rem' }}>
              {[{ num: '10K+', label: 'Users' }, { num: '500+', label: 'Events' }, { num: '50K+', label: 'Tickets Sold' }, { num: '4.9★', label: 'Rating' }].map((s, i) => (
                <div key={i} style={{ background: 'rgba(255,255,255,0.12)', borderRadius: '12px', padding: '0.8rem', textAlign: 'center' }}>
                  <p style={{ color: 'white', fontWeight: '800', fontSize: '1.2rem', margin: 0 }}>{s.num}</p>
                  <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '0.72rem', margin: 0 }}>{s.label}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default Register;
